// ScrollView contains a Button
// User flow:
// 1. Finger touches Button (ACTION_DOWN)
// 2. Finger starts moving vertically (ACTION_MOVE)

// ScrollView.onInterceptTouchEvent() logic:
// - Returns false for ACTION_DOWN (lets children handle it)
// - Returns true once vertical movement exceeds touch slop

class MyCustomView : View {
    private var tracking = false

    override fun onTouchEvent(event: MotionEvent): Boolean {
        when (event.action) {
            ACTION_DOWN -> {
                tracking = true
                highlight()
                return true  // consume DOWN
            }
            ACTION_MOVE -> {
                updateDragPosition(event.x, event.y)
                return true
            }
            ACTION_UP -> {
                tracking = false
                performAction()
                unhighlight()
                return true
            }
            // NOTE: No ACTION_CANCEL handler!
        }
        return false
    }
}
