class CustomSeekBar : View {
    private var isDragging = false
    private var thumbX = 0f
    private var startThumbX = 0f

    override fun onTouchEvent(event: MotionEvent): Boolean {
        when (event.action) {
            MotionEvent.ACTION_DOWN -> {
                isDragging = true
                startThumbX = thumbX
                return true
            }
            MotionEvent.ACTION_MOVE -> {
                if (isDragging) {
                    thumbX = event.x.coerceIn(0f, width.toFloat())
                    invalidate()
                }
                return true
            }
            MotionEvent.ACTION_UP -> {
                isDragging = false
                onValueChanged(thumbX / width)
                return true
            }
            MotionEvent.ACTION_CANCEL -> {
                isDragging = false
                thumbX = startThumbX  // snap back to original
                invalidate()
                return true
            }
        }
        return super.onTouchEvent(event)
    }
}
